<?php require __DIR__.'/../includes/bootstrap.php';require_admin();if(!brands_schema_ready())redirect('../upgrade-brands-imports.php');$allowed=['approved','rejected','suspended'];if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$id=(int)($_POST['brand_id']??0);$action=$_POST['action']??'';$notes=trim($_POST['review_notes']??'');if(!in_array($action,$allowed,true)){flash('error','Invalid action.');redirect('brands.php');}$s=db()->prepare('SELECT * FROM brands WHERE id=?');$s->execute([$id]);$b=$s->fetch();if(!$b){flash('error','Brand not found.');redirect('brands.php');}db()->beginTransaction();try{db()->prepare('UPDATE brands SET status=?,reviewed_by=?,reviewed_at=NOW(),review_notes=? WHERE id=?')->execute([$action,(int)user()['id'],$notes?:null,$id]);if($action==='approved')db()->prepare("UPDATE brand_members SET brand_role=CASE WHEN brand_role='pending_manager' THEN 'manager' ELSE brand_role END,status='active' WHERE brand_id=?")->execute([$id]);elseif($action==='rejected')db()->prepare("UPDATE brand_members SET status='rejected' WHERE brand_id=? AND status='pending'")->execute([$id]);db()->prepare('INSERT INTO brand_approval_history(brand_id,action,notes,acted_by) VALUES(?,?,?,?)')->execute([$id,$action,$notes?:null,(int)user()['id']]);db()->commit();flash('success',$b['name'].' marked '.ucfirst($action).'.');}catch(Throwable $e){db()->rollBack();flash('error',$e->getMessage());}redirect('brands.php');}$status=$_GET['status']??'pending';if(!in_array($status,['pending','approved','rejected','suspended','draft','all'],true))$status='pending';$sql='SELECT b.*,c.name company_name,u.display_name submitter_name,u.email submitter_email FROM brands b JOIN companies c ON c.id=b.company_id JOIN users u ON u.id=b.submitted_by'.($status==='all'?'':' WHERE b.status=?').' ORDER BY b.created_at DESC';$s=db()->prepare($sql);$s->execute($status==='all'?[]:[$status]);$brands=$s->fetchAll();app_header('Brand Approvals');?><section class="dashboard-hero"><p class="eyebrow">ADMINISTRATION</p><h1>Brand Approvals</h1><p>Review brands submitted under approved companies.</p></section><p class="admin-actions"><a class="button ghost" href="companies.php">Companies</a><a class="button ghost" href="imports.php">Import Center</a><a class="button ghost" href="users.php">Users</a></p><div class="filter-links"><?php foreach(['pending','draft','approved','rejected','suspended','all'] as $x):?><a class="<?=$status===$x?'active':''?>" href="?status=<?=$x?>"><?=e(ucfirst($x))?></a><?php endforeach?></div><div class="company-admin-list"><?php foreach($brands as $b):?><article class="app-card company-review-card"><div><span class="status-badge <?=e($b['status'])?>"><?=e(ucfirst($b['status']))?></span><h2><?=e($b['name'])?></h2><p><strong>Parent company:</strong> <?=e($b['company_name'])?></p><p><?=e($b['short_description'])?></p><p class="muted">Submitted by <?=e($b['submitter_name'])?> (<?=e($b['submitter_email'])?>)</p><p><a href="<?=e(base_url('brand/dashboard.php?id='.(int)$b['id']))?>">Open brand dashboard</a></p></div><form method="post" class="company-review-form"><?=csrf_field()?><input type="hidden" name="brand_id" value="<?=(int)$b['id']?>"><label>Review notes<textarea name="review_notes"><?=e($b['review_notes'])?></textarea></label><div class="admin-actions"><button class="button primary small" name="action" value="approved">Approve</button><button class="button ghost small" name="action" value="rejected">Reject</button><button class="button ghost small" name="action" value="suspended">Suspend</button></div></form></article><?php endforeach?><?php if(!$brands):?><article class="app-card"><h2>No <?=e($status)?> brands</h2></article><?php endif?></div><?php app_footer();
